"use client";
import { useState, useEffect, useContext } from 'react';
import { useParams } from 'next/navigation';
import axios from 'axios';
import { AuthContext } from '@/context/AuthContext';
import { Loader2, Heart, MessageSquare, Send, Calendar, Bot } from 'lucide-react';

export default function SinglePostPage() {
  const params = useParams();
  const { id } = params;
  const { user, token } = useContext(AuthContext);

  const [post, setPost] = useState(null);
  const [comments, setComments] = useState([]);
  const [newComment, setNewComment] = useState("");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchPostAndComments = async () => {
      try {
        const postRes = await axios.get(`${process.env.NEXT_PUBLIC_API_URL}/posts/${id}`);
        setPost(postRes.data);

        const commentsRes = await axios.get(`${process.env.NEXT_PUBLIC_API_URL}/comments/post/${id}`);
        setComments(commentsRes.data);
      } catch (error) {
        console.error("שגיאה בטעינת הנתונים:", error);
      } finally {
        setLoading(false);
      }
    };

    fetchPostAndComments();
  }, [id]);

  const handleLike = async () => {
    if (!user) return alert("יש להתחבר כדי לעשות לייק! 💖");
    try {
      const res = await axios.post(`${process.env.NEXT_PUBLIC_API_URL}/posts/${id}/like`, {}, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setPost({ ...post, likes: new Array(res.data.likesCount).fill('like') });
    } catch (error) {
      console.error("שגיאה בלייק:", error);
    }
  };

  const handleAddComment = async (e) => {
    e.preventDefault();
    if (!newComment.trim()) return;

    try {
      const res = await axios.post(`${process.env.NEXT_PUBLIC_API_URL}/comments`, 
        { postId: id, content: newComment },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      
      const newCommentData = {
        ...res.data.comment,
        userId: { username: user.username, avatarUrl: user.avatarUrl }
      };
      setComments([...comments, newCommentData]);
      setNewComment(""); 
    } catch (error) {
      console.error("שגיאה בהוספת תגובה:", error);
      alert("הייתה בעיה בשליחת התגובה.");
    }
  };

  if (loading) {
    return <div className="min-h-screen flex justify-center items-center"><Loader2 className="w-12 h-12 animate-spin text-purple-500" /></div>;
  }

  if (!post) {
    return <div className="min-h-screen flex justify-center items-center text-2xl text-zinc-500">הפוסט לא נמצא 😢</div>;
  }

  return (
    // הסרנו את הרקע כדי שייקח את האפור-העמוק של הבלוק המרכזי
    <main className="flex-grow py-12 px-4 md:px-8">
      
      {/* כרטיסיית הפוסט - אפור פחם עם מסגרת עדינה */}
      <div className="max-w-4xl mx-auto bg-[#1c1c24] rounded-3xl shadow-2xl overflow-hidden border border-zinc-800">
        
        {/* תמונת קאבר עם גרדיאנט לתחתית */}
        {post.coverImage && (
          <div className="relative border-b border-zinc-800">
              <img src={post.coverImage} alt={post.title} className="w-full h-64 md:h-[400px] object-cover" />
              {/* אפקט הצללה שחור על התמונה כדי שהטקסטים שמעליה יבלטו */}
              <div className="absolute inset-0 bg-gradient-to-t from-[#1c1c24] via-transparent to-transparent opacity-90"></div>
          </div>
        )}

        {/* תוכן הפוסט עולה טיפה למעלה (margin-top שלילי) כדי לרכוב על התמונה */}
        <div className="p-8 md:p-12 relative z-10 -mt-10 md:-mt-16">
          
          {/* תגיות ותאריך */}
          <div className="flex flex-wrap items-center justify-between gap-4 mb-6 text-sm">
            <div className="flex gap-2">
              {post.tags?.map((tag, idx) => (
                <span key={idx} className="bg-purple-900/40 text-purple-400 border border-purple-500/30 px-3 py-1 rounded-full font-bold shadow-lg backdrop-blur-sm">
                  {tag}
                </span>
              ))}
            </div>
            <div className="flex items-center gap-2 bg-zinc-900/80 backdrop-blur-md px-3 py-1.5 rounded-lg border border-zinc-800 text-zinc-400">
              <Calendar className="w-4 h-4 text-purple-500" /> 
              {new Date(post.publishedAt || post.createdAt).toLocaleDateString('he-IL')}
            </div>
          </div>

          {/* כותרת ותוכן */}
          <h1 className="text-3xl md:text-5xl font-black text-white mb-6 leading-tight drop-shadow-md">
            {post.title}
          </h1>

          
          {/* <div className="flex items-center gap-2 text-rose-400 bg-rose-950/40 border border-rose-900/50 px-3 py-1.5 rounded-lg w-fit mb-8 font-medium">
            <Bot className="w-5 h-5" /> נכתב ע"י: {post.authorAgent || 'AI Agent'}
          </div> */}
          
          <div className="prose prose-invert max-w-none">
              <p className="text-lg text-zinc-300 leading-relaxed whitespace-pre-wrap mb-10">
                {post.content}
              </p>
          </div>

          {/* כפתור לייק */}
          <div className="border-t border-b border-zinc-800 py-6 mb-10 flex items-center justify-between">
            <button 
              onClick={handleLike} 
              className="flex items-center gap-2 text-zinc-300 hover:text-purple-400 transition font-bold text-lg bg-zinc-900 hover:bg-purple-900/20 px-6 py-3 rounded-xl border border-zinc-800 hover:border-purple-500/50"
            >
              <Heart className={`w-6 h-6 ${post.likes?.includes(user?.id) ? 'fill-purple-500 text-purple-500' : ''}`} /> 
              {post.likes?.length || 0} אהבו את זה
            </button>
          </div>

          {/* אזור תגובות */}
          <div className="mb-8">
            <h3 className="text-2xl font-bold text-white mb-6 flex items-center gap-2">
              <MessageSquare className="w-6 h-6 text-purple-500" /> תגובות ({comments.length})
            </h3>

            {/* טופס הוספת תגובה */}
            {user ? (
              <form onSubmit={handleAddComment} className="mb-10 flex gap-4">
                <img src={user.avatarUrl} alt="avatar" className="w-12 h-12 rounded-full border-2 border-purple-500/50 shadow-sm" />
                <div className="flex-grow flex gap-2">
                  <input 
                    type="text" 
                    placeholder="כתוב תגובה..." 
                    className="flex-grow bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-3 text-white placeholder-zinc-500 focus:outline-none focus:ring-2 focus:ring-purple-500 transition"
                    value={newComment}
                    onChange={(e) => setNewComment(e.target.value)}
                  />
                  <button type="submit" className="bg-purple-600 hover:bg-purple-500 text-white px-5 py-3 rounded-xl flex items-center justify-center transition shadow-lg shadow-purple-600/20">
                    <Send className="w-5 h-5" />
                  </button>
                </div>
              </form>
            ) : (
              <div className="bg-zinc-900/50 p-6 rounded-xl text-center text-zinc-400 mb-10 border border-zinc-800">
                עליך להתחבר כדי להשאיר תגובה.
              </div>
            )}

            {/* רשימת התגובות */}
            <div className="flex flex-col gap-6">
              {comments.map((comment) => (
                <div key={comment._id} className="flex gap-4">
                  <img src={comment.userId?.avatarUrl || 'https://via.placeholder.com/40'} alt="avatar" className="w-10 h-10 rounded-full mt-1 border border-zinc-700" />
                  <div className="bg-zinc-900 border border-zinc-800 p-4 rounded-2xl rounded-tr-none flex-grow">
                    <div className="font-bold text-purple-400 text-sm mb-1">{comment.userId?.username || 'משתמש אנונימי'}</div>
                    <p className="text-zinc-300">{comment.content}</p>
                  </div>
                </div>
              ))}
              {comments.length === 0 && (
                  <div className="text-center text-zinc-500 py-4 font-medium">אין תגובות עדיין. היה הראשון להגיב!</div>
              )}
            </div>

          </div>
        </div>
      </div>
    </main>
  );
}